const e={"CM-1":{title:"Policy and Procedures",body:"[ORG] has developed, documented, and disseminated a Configuration Management Policy requiring all [SYSTEM] components to be configured per approved baselines derived from DISA STIGs and SRGs. Reviewed annually. The [ISSO] is responsible for implementing CM controls.",tools:[]},"CM-2":{title:"Baseline Configuration",body:"Documented baselines for all components derived from DISA STIGs for [TOOL:win11], [TOOL:server2016], [TOOL:server2019], [TOOL:server2022], [TOOL:juniper], [TOOL:cisco9300], [TOOL:paloalto], and [TOOL:ivanti]. Stored in [ORG]'s CM repository. Deviations require CCB approval. Validated via [TOOL:scap] and [TOOL:stig] quarterly.",tools:["win11","server2016","server2019","server2022","juniper","cisco9300","paloalto","ivanti","scap","stig","acas"]},"CM-2(1)":{title:"Baseline Configuration | Reviews and Updates",body:"[ORG] reviews and updates the baseline configuration for [SYSTEM] annually and when major security issues are discovered or following software updates. The [ISSO] coordinates baseline reviews with system administrators. Updated STIGs from DISA are incorporated within 30 days of release. [TOOL:scap] content is updated to reflect current STIG versions. Baseline updates are managed through the CCB process.",tools:["scap","stig"]},"CM-2(2)":{title:"Baseline Configuration | Automation Support for Accuracy",body:"[SYSTEM] maintains the currency, completeness, and accuracy of the baseline configuration using [TOOL:acas]/[TOOL:tenablesc] automated configuration assessment. [TOOL:scap] provides automated STIG compliance verification against documented baselines. [TOOL:crowdstrike] detects deviations from baseline software inventory. Automated tools generate compliance reports reviewed by the [ISSO] weekly.",tools:["acas","tenablesc","scap","crowdstrike"]},"CM-2(3)":{title:"Baseline Configuration | Retention of Previous Configurations",body:"[SYSTEM] retains previous versions of baseline configurations for [SYSTEM] to support rollback when necessary. Configuration backups are maintained for a minimum of 3 prior versions. [TOOL:server2022] system state backups preserve previous configurations. Network device configurations ([TOOL:juniper], [TOOL:cisco9300], [TOOL:paloalto]) are backed up before each change. Previous configurations are stored in [ORG]'s CM repository and available for rollback within 2 hours.",tools:["server2022","juniper","cisco9300","paloalto"]},"CM-2(7)":{title:"Baseline Configuration | Configure Systems and Components for High-Risk Areas",body:"[SYSTEM] issues systems with approved hardened configurations to individuals traveling to high-risk locations or connecting from high-risk networks. Systems configured for high-risk areas have: minimal software installation, enhanced logging via [TOOL:splunk], aggressive [TOOL:crowdstrike] prevention policies, and mandatory [TOOL:ivanti] VPN with no split-tunnel. The [ISSO] approves high-risk configurations and reviews them quarterly.",tools:["splunk","crowdstrike","ivanti"]},"CM-3":{title:"Configuration Change Control",body:"All changes managed through formal CCB process. Changes submitted via [ORG]'s change management system, reviewed by [ISSO] for security impact, approved by CCB, tested in non-production, implemented during approved maintenance windows. Emergency changes authorized by [ISSM] and documented within 24 hours. Changes logged and audited via [TOOL:splunk]. [TOOL:crowdstrike] detects unauthorized changes.",tools:["splunk","crowdstrike"]},"CM-3(1)":{title:"Configuration Change Control | Automated Documentation, Notification, and Prohibition",body:"[SYSTEM] employs automated mechanisms to document proposed changes, notify defined approval authorities, and highlight approvals not received. [ORG]'s change management ticketing system provides automated notification workflows. [TOOL:splunk] monitors for configuration changes outside the approved change window. Changes implemented without CCB approval are detected by [TOOL:crowdstrike] and [TOOL:splunk] and generate immediate alerts to the [ISSO].",tools:["splunk","crowdstrike"]},"CM-3(2)":{title:"Configuration Change Control | Testing, Validation, and Documentation",body:"[SYSTEM] tests, validates, and documents changes before implementing on the operational system. All proposed changes are tested in a non-production environment that mirrors [SYSTEM]. [TOOL:acas] scans the test environment after changes to identify new vulnerabilities. [TOOL:scap] validates STIG compliance after configuration changes. Test results and approvals are documented before production implementation.",tools:["acas","scap"]},"CM-3(4)":{title:"Configuration Change Control | Security and Privacy Representatives",body:"[TOOL:isso] reviews and approves all configuration changes to [SYSTEM] for security and privacy impact before implementation. The [ISSO] participates in all CCB meetings. Configuration change decisions consider security and privacy impact documented in Security Impact Analysis (SIA). Changes with significant security impact are escalated to the [ISSM] and [AO] per the authorization process.",tools:[]},"CM-3(6)":{title:"Configuration Change Control | Cryptography Management",body:"[SYSTEM] ensures cryptographic mechanisms used to protect [SYSTEM] information are under configuration management. Changes to cryptographic configurations require [ISSO] approval. FIPS compliance of cryptographic mechanisms is validated via [TOOL:scap] after changes. [TOOL:gpo] manages Windows cryptographic settings. [TOOL:paloalto] and [TOOL:ivanti] cryptographic configurations are included in the CM program.",tools:["scap","gpo","paloalto","ivanti"]},"CM-4":{title:"Impact Analyses",body:"The [ISSO] conducts Security Impact Analysis for all proposed changes using NIST SP 800-128 guidance. Changes categorized as minor, moderate, or significant. Significant changes require [AO] notification and may require reauthorization. [TOOL:acas] scans conducted after changes. Impact analysis results documented in the change management record.",tools:["acas"]},"CM-4(1)":{title:"Impact Analyses | Separate Test Environments",body:"[SYSTEM] analyzes changes to the system in a separate test environment before implementation in the operational environment. The test environment mirrors [SYSTEM] configuration. Security impact analysis is conducted on test results before production implementation. [TOOL:acas] scans validate the test environment after changes. The [ISSO] approves test results before production change authorization.",tools:["acas"]},"CM-5":{title:"Access Restrictions for Change",body:"Only authorized change implementers can make production changes. [TOOL:ad] RBAC restricts production access to designated administrators. [TOOL:gpo] prevents unauthorized software installation. Changes implemented only during approved maintenance windows. [TOOL:splunk] logs all production changes. [TOOL:crowdstrike] alerts on unauthorized change attempts.",tools:["ad","gpo","splunk","crowdstrike"]},"CM-5(1)":{title:"Access Restrictions for Change | Automated Access Enforcement and Audit Records",body:"[SYSTEM] enforces access restrictions for changes and generates audit records of the enforcement actions. [TOOL:ad] RBAC enforces access restrictions with automatic audit trail generation. [TOOL:splunk] aggregates change authorization audit records. [TOOL:crowdstrike] detects and alerts on attempts to bypass change control restrictions. Automated enforcement ensures no production changes occur outside the approved process.",tools:["ad","splunk","crowdstrike"]},"CM-6":{title:"Configuration Settings (STIGs/SRGs)",body:"DISA STIGs applied to all components: [TOOL:win11] STIG, Windows Server STIGs ([TOOL:server2016],[TOOL:server2019],[TOOL:server2022]), Network Infrastructure STIGs ([TOOL:juniper],[TOOL:cisco9300]), [TOOL:paloalto] STIG, [TOOL:ivanti] VPN SRG. [TOOL:gpo] enforces Windows settings. [TOOL:scap] validates STIG compliance quarterly. [TOOL:acas]/[TOOL:tenablesc] validates weekly. Non-compliant settings documented in POAM.",tools:["win11","server2016","server2019","server2022","juniper","cisco9300","paloalto","ivanti","gpo","scap","acas","tenablesc","stig"]},"CM-6(1)":{title:"Configuration Settings | Automated Management and Verification",body:"[SYSTEM] employs automated mechanisms to centrally manage, apply, and verify configuration settings. [TOOL:gpo] centrally manages and enforces configuration settings across all Windows endpoints. [TOOL:scap] automated scanning verifies configuration compliance against STIG baselines. [TOOL:acas]/[TOOL:tenablesc] provides automated configuration assessment. [TOOL:tenablesc] reports configuration deviations to the [ISSO] weekly.",tools:["gpo","scap","acas","tenablesc"]},"CM-6(2)":{title:"Configuration Settings | Respond to Unauthorized Changes",body:"[SYSTEM] takes action in response to unauthorized changes to configuration settings. [TOOL:crowdstrike] detects unauthorized configuration changes in real time and alerts the [ISSO] within minutes. [TOOL:splunk] correlates unauthorized change events with user identity and context. The [ISSO] investigates and remediates unauthorized changes within 4 hours. Persistent unauthorized changes trigger escalation to the [ISSM] and potential incident declaration.",tools:["crowdstrike","splunk"]},"CM-7":{title:"Least Functionality",body:"[TOOL:gpo] disables unnecessary services on Windows. [TOOL:paloalto] app-layer controls restrict traffic to approved applications. [TOOL:hbss] HIPS blocks unauthorized execution. [TOOL:zscaler] restricts web access to approved categories. Unnecessary ports/protocols disabled per DISA STIGs. Approved ports/protocols/services list reviewed quarterly.",tools:["gpo","paloalto","hbss","zscaler","stig"]},"CM-7(1)":{title:"Least Functionality | Periodic Review",body:"[ORG] reviews [SYSTEM] to identify and eliminate unnecessary functions, ports, protocols, and services quarterly. The [ISSO] conducts least functionality reviews with system administrators. [TOOL:acas] identifies unnecessary open ports and services. [TOOL:crowdstrike] identifies unnecessary running processes. Review results drive configuration changes managed through the CCB process.",tools:["acas","crowdstrike"]},"CM-7(2)":{title:"Least Functionality | Prevent Program Execution",body:"[SYSTEM] prevents execution of programs in accordance with the approved software list. [TOOL:gpo] AppLocker policies enforce application allowlisting on Windows systems. [TOOL:hbss] HIPS prevents execution of unauthorized applications. [TOOL:crowdstrike] blocks execution of malicious and unauthorized programs using behavioral prevention. Application execution prevention is validated via [TOOL:stig] checks quarterly.",tools:["gpo","hbss","crowdstrike","stig"]},"CM-7(4)":{title:"Least Functionality | Unauthorized Software | Blacklisting",body:"[SYSTEM] identifies and prevents use of unauthorized software by maintaining a list of prohibited software. [TOOL:gpo] software restriction policies block known prohibited applications. [TOOL:hbss] HIPS blocks execution of software on the prohibited list. [TOOL:crowdstrike] prevents execution of known malicious software using threat intelligence. The prohibited software list is maintained by the [ISSO] and updated monthly based on [TOOL:crowdstrike] threat intelligence.",tools:["gpo","hbss","crowdstrike"]},"CM-7(5)":{title:"Least Functionality | Authorized Software | Allowlisting",body:"[SYSTEM] employs an allowlist of authorized software to control what can execute. The authorized software list is maintained by the [ISSO] and approved by the [ISSM]. [TOOL:gpo] AppLocker enforces the allowlist on Windows systems. [TOOL:crowdstrike] application control enforces execution policies. Software not on the allowlist is blocked by default. The allowlist is reviewed quarterly and updated through the CCB process.",tools:["gpo","crowdstrike"]},"CM-8":{title:"System Component Inventory",body:"[TOOL:acas]/[TOOL:tenablesc] performs automated asset discovery during weekly scans. [TOOL:crowdstrike] maintains real-time endpoint inventory. [ISSO] reviews and reconciles monthly. Unauthorized assets trigger alerts within 24 hours. Inventory maintained in [TOOL:emass] and synchronized quarterly.",tools:["acas","tenablesc","crowdstrike","emass"]},"CM-8(1)":{title:"System Component Inventory | Updates During Installation and Removal",body:"[SYSTEM] updates the inventory of system components as an integral part of component installations, removals, and system updates. The [ISSO] is notified of all hardware additions and removals. [TOOL:acas] discovers new components during the next scheduled scan. [TOOL:crowdstrike] enrollment is required within 24 hours of new endpoint deployment. Inventory is updated in [TOOL:emass] within 5 business days of component changes.",tools:["acas","crowdstrike","emass"]},"CM-8(2)":{title:"System Component Inventory | Automated Maintenance",body:"[SYSTEM] employs automated mechanisms to maintain an up-to-date, complete, and accurate inventory of system components. [TOOL:acas]/[TOOL:tenablesc] continuously discovers and inventories network-connected assets. [TOOL:crowdstrike] provides real-time endpoint software and hardware inventory. Automated inventory discrepancies generate [TOOL:splunk] alerts for [ISSO] review. The [ISSO] reconciles automated inventory with the [TOOL:emass] inventory monthly.",tools:["acas","tenablesc","crowdstrike","splunk","emass"]},"CM-8(3)":{title:"System Component Inventory | Automated Unauthorized Component Detection",body:"[SYSTEM] employs automated mechanisms to detect the presence of unauthorized hardware, software, and firmware components. [TOOL:acas] network discovery identifies components not in the approved inventory. [TOOL:crowdstrike] detects new software installations on enrolled endpoints. [TOOL:splunk] alerts the [ISSO] within 4 hours of unauthorized component detection. Unauthorized components are investigated and remediated immediately.",tools:["acas","crowdstrike","splunk"]},"CM-9":{title:"Configuration Management Plan",body:"[ORG] maintains a CMP for [SYSTEM] defining CM roles, responsibilities, processes, and tools. The CMP documents baseline CM, change control procedures, configuration monitoring strategy, and CI identification. Reviewed annually. Maintained in [TOOL:emass]. All CM personnel trained on CMP procedures.",tools:["emass"]},"CM-10":{title:"Software Usage Restrictions",body:"Software used per applicable license agreements. Software inventory maintained for license compliance. [TOOL:gpo] restricts installation to authorized apps. [TOOL:crowdstrike] monitors for unauthorized execution. Open-source requires [ISSO] and legal review. License compliance reviewed annually.",tools:["gpo","crowdstrike"]},"CM-11":{title:"User-Installed Software",body:"[TOOL:gpo] AppLocker policies restrict user-installed software on Windows systems. Only [ISSO]-approved software may be installed. [TOOL:hbss] HIPS detects and blocks unauthorized installation. [TOOL:crowdstrike] monitors for unauthorized execution. Violations logged to [TOOL:splunk] and reported to [ISSM].",tools:["gpo","hbss","crowdstrike","splunk"]},"CM-11(2)":{title:"User-Installed Software | Software Installation with Privileged Status",body:"[SYSTEM] prohibits installation of software by users without explicit privileged status. Only system administrators with [ISSO]-authorized privileged accounts can install software on [SYSTEM]. [TOOL:gpo] enforces this restriction through UAC and software restriction policies. [TOOL:hbss] blocks installation attempts by non-privileged users. Installation attempts are logged to [TOOL:splunk] and reviewed weekly.",tools:["gpo","hbss","splunk"]},"CM-12":{title:"Information Location",body:"[ORG] identifies and documents the location of CUI and PII within [SYSTEM]. Data location is documented in the SSP and data flow diagrams maintained in [TOOL:emass]. [TOOL:paloalto] DLP policies enforce data handling based on location and classification. [TOOL:acas] scans identify unintended data exposure. Data location documentation is reviewed annually and when system architecture changes.",tools:["emass","paloalto","acas"]},"CM-14":{title:"Signed Components",body:"[SYSTEM] prevents the installation of software without verification that the component has been digitally signed using a certificate recognized and approved by [ORG]. [TOOL:gpo] enforces code signing requirements for Windows software. [TOOL:crowdstrike] validates software signatures before execution. [TOOL:wsus] verifies Microsoft patch signatures before deployment. Unsigned software is blocked by default and requires [ISSO] approval for exception.",tools:["gpo","crowdstrike","wsus"]}};export{e as default};
